function isAliveNextGeneration(cell: Cell, alive: Set<string>): boolean {
  const [x, y] = cell;
  const liveNeighbors = countLiveNeighbors(x, y, alive);
  const wasAlive = alive.has(cellKey(x, y));
  return wasAlive ? liveNeighbors === 2 || liveNeighbors === 3 : liveNeighbors === 3;
}

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const alive = new Set(liveCells.map(([x, y]) => cellKey(x, y)));

  const candidates = new Map<string, Cell>();
  for (const [x, y] of liveCells) {
    candidates.set(cellKey(x, y), [x, y]);
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      candidates.set(cellKey(nx, ny), [nx, ny]);
    }
  }

  return [...candidates.values()].filter((cell) => isAliveNextGeneration(cell, alive));
}
